commands.cmd:
interval=1
s1=$(cat /proc/diskstats) || { echo "diskstats read 1 failed" >&2; exit 1; }
sleep "$interval"
s2=$(cat /proc/diskstats) || { echo "diskstats read 2 failed" >&2; exit 1; }
printf '%s\n===\n%s\n' "$s1" "$s2" | awk -v iv="$interval" '
  BEGIN{ phase=1; ms=iv*1000 }
  /^===$/{ phase=2; next }
  {
    dev=$3
    if (dev ~ /^(loop|ram|dm-)/) next
    # /proc/diskstats fields: 4=reads 8=writes 13=io_ticks(ms in I/O)
    if (phase==1){ r1[dev]=$4; w1[dev]=$8; t1[dev]=$13; seen[dev]=1 }
    else        { r2[dev]=$4; w2[dev]=$8; t2[dev]=$13 }
  }
  END{
    for (d in seen){
      dt = t2[d]-t1[d]
      ops = (r2[d]-r1[d]) + (w2[d]-w1[d])
      util = (ms>0 ? dt/ms*100 : 0); if (util<0) util=0
      awaitms = (ops>0 ? dt/ops : 0); if (awaitms<0) awaitms=0
      printf "%s\t%.1f\t%.2f\t%d\n", d, util, awaitms, ops
    }
  }' \
  | sort \
  | awk -F'\t' '
    BEGIN{ printf "{\"results\":["; sep="" }
    {
      printf "%s{\"device\":\"%s\",\"util_pct\":\"%s\",\"await_ms\":\"%s\",\"ops\":%d}", sep, $1, $2, $3, $4
      sep=","
    }
    END{ printf "]}" }' || exit 1
